/**
 * User API 服务
 * Generated by DDF Engine
 */

import request from '@/utils/request'

/**
 * 分页列表
 */
export function getUserList(params) {
  return request({
    url: '/api/user',
    method: 'get',
    params,
  })
}

/**
 * 详情
 */
export function getUser(id) {
  return request({
    url: `/api/user/${id}`,
    method: 'get',
  })
}

/**
 * 创建
 */
export function createUser(data) {
  return request({
    url: '/api/user',
    method: 'post',
    data,
  })
}

/**
 * 更新
 */
export function updateUser(id, data) {
  return request({
    url: `/api/user/${id}`,
    method: 'put',
    data,
  })
}

/**
 * 删除
 */
export function deleteUser(id) {
  return request({
    url: `/api/user/${id}`,
    method: 'delete',
  })
}
